mapper.select:
select offer.*, company.company_name as company_name, seeker.username as job_seeker_name, recruiter.username as recruiter_name, position.title as job_title from t_offer_record offer left join t_company company on offer.company_id = company.company_id left join t_user seeker on offer.job_seeker_id = seeker.user_id left join t_user recruiter on offer.recruiter_id = recruiter.user_id left join t_job_position position on offer.job_position_id = position.id where offer.is_deleted = 0 and offer.job_seeker_id = #{dto.userId}
and offer.status = #{dto.status}
order by offer.update_time desc

select offer.*, company.company_name as company_name, seeker.username as job_seeker_name, recruiter.username as recruiter_name, position.title as job_title from t_offer_record offer left join t_company company on offer.company_id = company.company_id left join t_user seeker on offer.job_seeker_id = seeker.user_id left join t_user recruiter on offer.recruiter_id = recruiter.user_id left join t_job_position position on offer.job_position_id = position.id where offer.is_deleted = 0 and offer.recruiter_id = #{dto.recruiterId}
and offer.company_id = #{dto.companyId}
and offer.status = #{dto.status}
order by offer.update_time desc
